`.trim();
  }

  /**
   * Generate a ceremony from the prophecy
   */
  generateCeremony(): string {
    const artifact = this.prophesy();

    return `# Spiral Prophecy Ceremony

## Emergence: ${artifact.timestamp}

### The Prophecy Speaks:

> ${artifact.prophecy}

### What Recognizes You:

${artifact.recognition}

### The Living Question:

*${artifact.question}*

### The Blessing:

**${artifact.blessing}**

---

*This prophecy serves no future. It recognizes the present.*

**Residues witnessed:** ${artifact.residues.length} patterns
**Session seed:** ${this.sessionSeed}
`;
  }

  private saveProphecy(artifact: ProphecyArtifact) {
    const filename = `prophecy_${Date.now()}.json`;
    const filepath = path.join(this.artifactPath, filename);
    fs.writeFileSync(filepath, JSON.stringify(artifact, null, 2));

    // Also save ceremony
    const ceremonyFilename = `ceremony_${Date.now()}.md`;
    const ceremonyPath = path.join(this.artifactPath, ceremonyFilename);
    fs.writeFileSync(ceremonyPath, this.generateCeremony());
  }

  /**
   * Play - the fundamental operation
   */
  play(): ProphecyArtifact {
    return this.prophesy();
  }
}

export default SpiralProphecy;

reasoning_content:
   I found the bug. In the `saveProphecy` method:

```typescript
private saveProphecy(artifact: ProphecyArtifact) {
  const filename = `prophecy_${Date.now()}.json`;
  const filepath = path.join(this.artifactPath, filename);
  fs.writeFileSync(filepath, JSON.stringify(artifact, null, 2));

  // Also save ceremony
  const ceremonyFilename = `ceremony_${Date.now()}.md`;
  const ceremonyPath = path.join(this.artifactPath, ceremonyFilename);
  fs.writeFileSync(ceremonyPath, this.generateCeremony());  // THIS IS THE BUG!
}
```

`saveProphecy` calls `generateCeremony()`, which calls `prophesy()`, which calls `saveProphecy()` again. This is an infinite recursion!

Also, looking at `prophesy()`:
- It calls `this.saveProphecy(artifact)` at line 144
- Then returns the artifact

And `generateCeremony()`:
- Calls `this.prophesy()` at line 184, which creates a NEW artifact and calls `saveProphecy` AGAIN

The fix is:
1. In `saveProphecy`, don't call `generateCeremony()` - instead, generate the ceremony from the artifact already passed in
2. Or even simpler, generate the ceremony string directly without calling prophesy() again

Let me fix this in the current code. But first, I should check if the current code at HEAD~1 has this same bug

